import Foundation

/// 사주 탭 NavigationStack 라우트.
///
/// WF4-01에서는 7케이스 모두 "준비중" placeholder로 라우트되며,
/// 실제 화면은 후속 슬라이스(WF4-02~07)에서 채워진다.
enum SajuRoute: Hashable {
    case elements
    case tenGods
    case learn
    case lesson(id: String)
    case daewoonPlaceholder
    case hapchungPlaceholder
    case yongsinPlaceholder
}

import Foundation

/// 4주(時/日/月/年) 한 기둥 모델.
///
/// `heavenlyStem`(천간)과 `earthlyBranch`(지지)는 한자 1자, `element`는
/// 색상 매핑용 오행 키("wood"/"fire"/"earth"/"metal"/"water").
struct Pillar: Hashable {
    enum Position: String, Hashable, CaseIterable {
        case hour
        case day
        case month
        case year
    }

    let position: Position
    let heavenlyStem: String
    let earthlyBranch: String
    let element: String
}

protocol UserSajuOriginProviding {
    /// 시·일·월·년 4기둥 (UI 정렬은 표시 단계에서 결정).
    var pillars: [Pillar] { get }

    /// 일간 한 줄 해석 — "일간 丙火 · 양의 불 — 따뜻함, 표현력, 리더십" 등.
    var dayMasterLine: String { get }
}

struct MockUserSajuOriginProvider: UserSajuOriginProviding {
    var pillars: [Pillar]
    var dayMasterLine: String

    init(
        pillars: [Pillar] = MockUserSajuOriginProvider.defaultPillars,
        dayMasterLine: String = "일간 丙火 · 양의 불 — 따뜻함, 표현력, 리더십"
    ) {
        self.pillars = pillars
        self.dayMasterLine = dayMasterLine
    }

    /// 와이어프레임 기본값 — 時庚申 / 日丙午 / 月辛卯 / 年庚午.
    static let defaultPillars: [Pillar] = [
        Pillar(position: .hour,  heavenlyStem: "庚", earthlyBranch: "申", element: "metal"),
        Pillar(position: .day,   heavenlyStem: "丙", earthlyBranch: "午", element: "fire"),
        Pillar(position: .month, heavenlyStem: "辛", earthlyBranch: "卯", element: "wood"),
        Pillar(position: .year,  heavenlyStem: "庚", earthlyBranch: "午", element: "fire"),
    ]
}

import Foundation

/// 사주 탭 홈의 5개 카테고리 카드 요약.
///
/// WF4-02에서 본격 사용. WF4-01에서는 시그니처 + 와이어프레임 기본값만
/// 노출하고 SajuTabView에서 직접 그리지 않는다.
struct SajuCategorySummary: Hashable {
    enum Kind: String, Hashable, CaseIterable {
        case elements
        case tenGods
        case daewoon
        case hapchung
        case yongsin
    }

    let kind: Kind
    let title: String
    let summary: String
    let badge: String?
}

protocol SajuCategoriesProviding {
    /// 5개 카테고리(elements/tenGods/daewoon/hapchung/yongsin) 요약.
    var categories: [SajuCategorySummary] { get }
}

struct MockSajuCategoriesProvider: SajuCategoriesProviding {
    var categories: [SajuCategorySummary]

    init(categories: [SajuCategorySummary] = MockSajuCategoriesProvider.defaultCategories) {
        self.categories = categories
    }

    /// 와이어프레임(screens-06-saju-tab.jsx) 기본 텍스트.
    static let defaultCategories: [SajuCategorySummary] = [
        SajuCategorySummary(
            kind: .elements,
            title: "오행 분포",
            summary: "火 3 · 金 2 · 木 1 · 水 0 · 土 2",
            badge: "부족: 水"
        ),
        SajuCategorySummary(
            kind: .tenGods,
            title: "십성 분석",
            summary: "비견·식신·정재 강함",
            badge: nil
        ),
        SajuCategorySummary(
            kind: .daewoon,
            title: "대운 · 세운",
            summary: "현재 丁巳 대운 (32~41)",
            badge: "전환기"
        ),
        SajuCategorySummary(
            kind: .hapchung,
            title: "합충형파",
            summary: "일지-시지 合, 월지 沖",
            badge: nil
        ),
        SajuCategorySummary(
            kind: .yongsin,
            title: "용신 · 희신",
            summary: "水 용신, 金 희신",
            badge: nil
        ),
    ]
}

import Foundation

/// 오행 분포 상세(WF4-04)의 데이터 시그니처.
///
/// 본 슬라이스(WF4-01)에서는 시그니처만 선언하고 실제 모델 확장은 WF4-04에서.
protocol SajuElementsDetailProviding {
    /// 오행 요약 한 줄(예: "火가 많고 水가 전혀 없는 사주").
    var summaryLine: String { get }
}

struct MockSajuElementsDetailProvider: SajuElementsDetailProviding {
    var summaryLine: String

    init(summaryLine: String = "火가 많고 水가 전혀 없는 사주") {
        self.summaryLine = summaryLine
    }
}

import Foundation

/// 십성 분석 상세(WF4-05)의 데이터 시그니처.
///
/// 본 슬라이스(WF4-01)에서는 시그니처만 선언하고 실제 모델 확장은 WF4-05에서.
protocol SajuTenGodsDetailProviding {
    /// 십성 요약 한 줄(예: "정재가 중심인 사주").
    var summaryLine: String { get }
}

struct MockSajuTenGodsDetailProvider: SajuTenGodsDetailProviding {
    var summaryLine: String

    init(summaryLine: String = "정재가 중심인 사주") {
        self.summaryLine = summaryLine
    }
}

import Foundation

/// 사주 학습 경로의 주간 진행 요약.
struct WeeklyProgress: Hashable {
    /// 이번 주 완료한 강의 수.
    let completed: Int
    /// 이번 주 목표 강의 수.
    let goal: Int
    /// 연속 학습 일수(예: 3일).
    let streakDays: Int
}

/// 사주 학습 경로의 한 코스(입문/오행/십성/대운 등).
struct SajuCourse: Hashable {
    enum Status: String, Hashable, CaseIterable {
        case completed
        case current
        case unfinished
        case locked
    }

    let id: String
    let title: String
    let lessonCount: Int
    /// 0.0 ~ 1.0 사이의 진행률.
    let progress: Double
    let status: Status
}

protocol SajuLearningPathProviding {
    var weeklyProgress: WeeklyProgress { get }
    var courses: [SajuCourse] { get }
}

struct MockSajuLearningPathProvider: SajuLearningPathProviding {
    var weeklyProgress: WeeklyProgress
    var courses: [SajuCourse]

    init(
        weeklyProgress: WeeklyProgress = WeeklyProgress(completed: 3, goal: 5, streakDays: 3),
        courses: [SajuCourse] = MockSajuLearningPathProvider.defaultCourses
    ) {
        self.weeklyProgress = weeklyProgress
        self.courses = courses
    }

    /// 와이어프레임(screens-06-saju-tab.jsx)의 4코스 — 입문 / 오행 / 십성 / 대운.
    static let defaultCourses: [SajuCourse] = [
        SajuCourse(id: "intro",    title: "입문", lessonCount: 7, progress: 1.0, status: .completed),
        SajuCourse(id: "elements", title: "오행", lessonCount: 5, progress: 0.6, status: .current),
        SajuCourse(id: "tenGods",  title: "십성", lessonCount: 8, progress: 0.3, status: .unfinished),
        SajuCourse(id: "daewoon",  title: "대운", lessonCount: 6, progress: 0.0, status: .locked),
    ]
}

import Foundation

/// 레슨 상세(WF4-07)의 데이터 시그니처.
///
/// 본 슬라이스(WF4-01)에서는 시그니처만 선언하고 실제 모델 확장은 WF4-07에서.
protocol SajuLessonProviding {
    /// 식별자에 대응하는 레슨 제목을 반환. nil이면 미존재.
    func lessonTitle(forId id: String) -> String?
}

struct MockSajuLessonProvider: SajuLessonProviding {
    var titlesById: [String: String]

    init(titlesById: [String: String] = MockSajuLessonProvider.defaultTitles) {
        self.titlesById = titlesById
    }

    func lessonTitle(forId id: String) -> String? {
        titlesById[id]
    }

    static let defaultTitles: [String: String] = [
        "L-001": "사주란 무엇인가",
        "L-002": "천간과 지지",
        "L-003": "오행의 의미",
    ]
}

import Foundation

/// 사주 탭(SajuTabView)이 필요로 하는 6종 providing을 한 곳에 모은 DI 컨테이너.
///
/// `@EnvironmentObject` 또는 생성자 주입으로 SajuTabView에 전달한다. 테스트 시
/// 임의 mock으로 6필드 각각을 교체할 수 있다.
final class SajuTabDependencies: ObservableObject {
    var userSajuOrigin: any UserSajuOriginProviding
    var categories: any SajuCategoriesProviding
    var elementsDetail: any SajuElementsDetailProviding
    var tenGodsDetail: any SajuTenGodsDetailProviding
    var learningPath: any SajuLearningPathProviding
    var lesson: any SajuLessonProviding

    init(
        userSajuOrigin: any UserSajuOriginProviding = MockUserSajuOriginProvider(),
        categories: any SajuCategoriesProviding = MockSajuCategoriesProvider(),
        elementsDetail: any SajuElementsDetailProviding = MockSajuElementsDetailProvider(),
        tenGodsDetail: any SajuTenGodsDetailProviding = MockSajuTenGodsDetailProvider(),
        learningPath: any SajuLearningPathProviding = MockSajuLearningPathProvider(),
        lesson: any SajuLessonProviding = MockSajuLessonProvider()
    ) {
        self.userSajuOrigin = userSajuOrigin
        self.categories = categories
        self.elementsDetail = elementsDetail
        self.tenGodsDetail = tenGodsDetail
        self.learningPath = learningPath
        self.lesson = lesson
    }

    static let mock = SajuTabDependencies()
}

import SwiftUI

/// 사주 탭 상단 고정 헤더.
///
/// 좌측 "사주" 타이틀 + 우측 원형 placeholder 아이콘. 후속 슬라이스에서
/// 우측 아이콘에 의미가 부여되면 교체된다.
struct SajuTabHeaderView: View {
    var onMenuTap: () -> Void = {}

    var body: some View {
        HStack(spacing: 12) {
            Text(String(localized: "saju.tab.title", defaultValue: "사주"))
                .font(.system(size: 15, weight: .bold))
                .foregroundStyle(DesignTokens.ink)
                .lineLimit(1)
                .minimumScaleFactor(0.7)
                .accessibilityIdentifier("SajuTabHeaderTitle")
                .accessibilityLabel(Text(String(localized: "saju.tab.title", defaultValue: "사주")))

            Spacer(minLength: 8)

            Button(action: onMenuTap) {
                Circle()
                    .stroke(DesignTokens.line2, lineWidth: 1)
                    .frame(width: 24, height: 24)
                    .contentShape(Rectangle())
                    .frame(width: 44, height: 44)
            }
            .buttonStyle(.plain)
            .accessibilityIdentifier("SajuTabHeaderMenuButton")
            .accessibilityLabel(Text(String(
                localized: "saju.tab.menu.label",
                defaultValue: "사주 메뉴"
            )))
        }
        .padding(.horizontal, 16)
        .padding(.vertical, 10)
        .background(DesignTokens.bg)
    }
}

import SwiftUI

/// 사주 탭 컨텐츠 슬롯 — 본 슬라이스(WF4-01)에서는 비어 있는 ScrollView +
/// "준비중" placeholder 텍스트만 렌더한다. 실제 컨텐츠는 WF4-02/03에서 채워진다.
struct SajuTabContentPlaceholderView: View {
    var body: some View {
        ScrollView {
            VStack(spacing: 0) {
                Spacer().frame(height: 80)
                Text(String(
                    localized: "saju.tab.content.placeholder",
                    defaultValue: "준비중"
                ))
                .font(.system(size: 14, weight: .regular))
                .foregroundStyle(DesignTokens.muted)
                .accessibilityIdentifier("SajuTabContentPlaceholderText")
                Spacer().frame(height: 200)
            }
            .frame(maxWidth: .infinity)
        }
        .accessibilityIdentifier("SajuTabContentPlaceholder")
    }
}

import SwiftUI

/// `SajuRoute` 목적지 placeholder.
///
/// 본 슬라이스(WF4-01)에서는 7케이스 모두 동일한 "준비중" 화면을 표시한다.
/// `lesson(id:)`는 화면에 식별자를 함께 표시해 associated value 전달을 검증한다.
/// WF4-04~07에서 각 라우트별 실제 화면으로 교체된다.
struct SajuPlaceholderDestinationView: View {
    let routeKey: String
    /// `lesson` 라우트의 경우에만 채워지는 식별자(예: "L-001").
    var identifier: String? = nil

    var body: some View {
        VStack(spacing: 12) {
            Text(String(
                localized: "saju.tab.content.placeholder",
                defaultValue: "준비중"
            ))
            .font(.system(size: 14, weight: .regular))
            .foregroundStyle(DesignTokens.muted)
            .accessibilityIdentifier("SajuPlaceholderDestination_\(routeKey)_Text")

            if let identifier {
                Text(identifier)
                    .font(.system(size: 13, weight: .semibold))
                    .foregroundStyle(DesignTokens.ink)
                    .accessibilityIdentifier("SajuPlaceholderDestination_\(routeKey)_Identifier")
            }
        }
        .padding()
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
        .background(DesignTokens.bg)
        .accessibilityElement(children: .contain)
        .accessibilityIdentifier("SajuPlaceholderDestination_\(routeKey)")
    }
}

/// 한 곳에서 라우트 → 목적지 View로 매핑한다.
@ViewBuilder
func sajuRouteDestination(for route: SajuRoute) -> some View {
    switch route {
    case .elements:
        SajuPlaceholderDestinationView(routeKey: "elements")
    case .tenGods:
        SajuPlaceholderDestinationView(routeKey: "tenGods")
    case .learn:
        SajuPlaceholderDestinationView(routeKey: "learn")
    case .lesson(let id):
        SajuPlaceholderDestinationView(routeKey: "lesson", identifier: id)
    case .daewoonPlaceholder:
        SajuPlaceholderDestinationView(routeKey: "daewoon")
    case .hapchungPlaceholder:
        SajuPlaceholderDestinationView(routeKey: "hapchung")
    case .yongsinPlaceholder:
        SajuPlaceholderDestinationView(routeKey: "yongsin")
    }
}

import SwiftUI

/// 사주 탭(TabBar index 2)의 컨테이너.
///
/// 구성: 상단 고정 Header / Divider / 사주 탭 전용 NavigationStack(컨텐츠 슬롯).
/// 본 슬라이스(WF4-01)에서는 컨텐츠 슬롯을 "준비중" placeholder로 둔다.
///
/// `accessibilityIdentifier("SajuTabRoot")`은 내부 hidden 마커에 부여한다 —
/// 외곽 VStack에 직접 부여하면 SwiftUI TabView가 그 식별자를 자식 트리로
/// 전파해 NavPush 트리거 등의 descendant 식별자가 가려진다(구현자 가이드).
struct SajuTabView: View {
    @EnvironmentObject var deps: SajuTabDependencies
    @State private var navigationPath: [SajuRoute] = []
    @State private var menuTapCount = 0

    private var showsUITestNavigationTriggers: Bool {
        let args = ProcessInfo.processInfo.arguments
        return args.contains("-openSajuTab") || args.contains("-openHome")
    }

    var body: some View {
        VStack(spacing: 0) {
            SajuTabHeaderView(onMenuTap: { menuTapCount += 1 })

            Rectangle()
                .fill(DesignTokens.headerBorder)
                .frame(height: 1)

            NavigationStack(path: $navigationPath) {
                SajuTabContentPlaceholderView()
                    .toolbar(.hidden, for: .navigationBar)
                    .navigationDestination(for: SajuRoute.self) { route in
                        sajuRouteDestination(for: route)
                    }
            }
        }
        .accessibilityElement(children: .contain)
        // Hidden tap-counter spy for header menu button.
        .overlay(alignment: .topLeading) {
            Text("\(menuTapCount)")
                .accessibilityIdentifier("SajuTabHeaderMenuTapCount")
                .opacity(0)
                .allowsHitTesting(false)
        }
        // Hidden marker so UI tests can locate the SajuTabView root via
        // app.otherElements["SajuTabRoot"] without polluting the TabView
        // child's outer identifier.
        .overlay(alignment: .topLeading) {
            Color.clear
                .frame(width: 1, height: 1)
                .accessibilityIdentifier("SajuTabRoot")
                .accessibilityHidden(false)
                .allowsHitTesting(false)
        }
        // Hidden push trigger buttons for UI tests (parallels HomeDashboardView).
        .overlay(alignment: .bottomLeading) {
            if showsUITestNavigationTriggers {
                VStack(spacing: 0) {
                    sajuUITestPushButton("SajuNavPush_elements") {
                        navigationPath.append(.elements)
                    }
                    sajuUITestPushButton("SajuNavPush_tenGods") {
                        navigationPath.append(.tenGods)
                    }
                    sajuUITestPushButton("SajuNavPush_learn") {
                        navigationPath.append(.learn)
                    }
                    sajuUITestPushButton("SajuNavPush_lessonL001") {
                        navigationPath.append(.lesson(id: "L-001"))
                    }
                    sajuUITestPushButton("SajuNavPush_daewoon") {
                        navigationPath.append(.daewoonPlaceholder)
                    }
                    sajuUITestPushButton("SajuNavPush_hapchung") {
                        navigationPath.append(.hapchungPlaceholder)
                    }
                    sajuUITestPushButton("SajuNavPush_yongsin") {
                        navigationPath.append(.yongsinPlaceholder)
                    }
                }
            }
        }
    }

    private func sajuUITestPushButton(
        _ identifier: String,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.black.opacity(0.001)
                .frame(width: 44, height: 44)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .accessibilityIdentifier(identifier)
        .accessibilityLabel(identifier)
    }
}

import SwiftUI

/// 4개 탭(홈/투자/사주/마이)을 담는 메인 컨테이너.
///
/// `-openSajuTab` 런치 인자가 주어지면 부팅 직후 사주 탭(index 2)이 활성화된다.
/// 사주 탭은 본 슬라이스(WF4-01)에서 도입된 `SajuTabView`. 투자·마이 탭은
/// 본 슬라이스 범위에서는 단순 "준비중" placeholder로 둔다.
struct MainTabContainerView: View {
    @EnvironmentObject var homeDeps: HomeDependencies
    @EnvironmentObject var sajuTabDeps: SajuTabDependencies
    @State private var selection: Int

    init(initialSelection: Int? = nil) {
        if let initialSelection {
            _selection = State(initialValue: initialSelection)
        } else {
            let parsed = MainTabContainerView.parseInitialSelection()
            _selection = State(initialValue: parsed)
        }
    }

    static func parseInitialSelection() -> Int {
        let args = ProcessInfo.processInfo.arguments
        if args.contains("-openSajuTab") { return 2 }
        return 0
    }

    var body: some View {
        TabView(selection: $selection) {
            // Tab 0 — 홈
            HomeDashboardView()
                .environmentObject(homeDeps)
                .tabItem {
                    Label(
                        String(localized: "saju.tab.home.label", defaultValue: "홈"),
                        systemImage: "house"
                    )
                }
                .tag(0)
                .accessibilityLabel(Text(String(
                    localized: "saju.tab.home.label",
                    defaultValue: "홈 탭"
                )))

            // Tab 1 — 투자 (placeholder)
            MainTabPlaceholderView(label: "investing")
                .tabItem {
                    Label(
                        String(localized: "saju.tab.invest.label", defaultValue: "투자"),
                        systemImage: "chart.line.uptrend.xyaxis"
                    )
                }
                .tag(1)
                .accessibilityLabel(Text(String(
                    localized: "saju.tab.invest.label",
                    defaultValue: "투자 탭"
                )))

            // Tab 2 — 사주
            SajuTabView()
                .environmentObject(sajuTabDeps)
                .tabItem {
                    Label(
                        String(localized: "saju.tab.title", defaultValue: "사주"),
                        systemImage: "sparkles"
                    )
                }
                .tag(2)
                .accessibilityLabel(Text(String(
                    localized: "saju.tab.tabBar.label",
                    defaultValue: "사주 탭"
                )))

            // Tab 3 — 마이 (placeholder)
            MainTabPlaceholderView(label: "my")
                .tabItem {
                    Label(
                        String(localized: "saju.tab.my.label", defaultValue: "마이"),
                        systemImage: "person.crop.circle"
                    )
                }
                .tag(3)
                .accessibilityLabel(Text(String(
                    localized: "saju.tab.my.label",
                    defaultValue: "마이 탭"
                )))
        }
    }
}

/// 투자/마이 탭의 비어있는 placeholder.
private struct MainTabPlaceholderView: View {
    let label: String

    var body: some View {
        VStack {
            Spacer()
            Text(String(
                localized: "saju.tab.content.placeholder",
                defaultValue: "준비중"
            ))
            .font(.system(size: 14))
            .foregroundStyle(DesignTokens.muted)
            .accessibilityIdentifier("MainTabPlaceholder_\(label)_Text")
            Spacer()
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(DesignTokens.bg)
        .accessibilityElement(children: .contain)
        .accessibilityIdentifier("MainTabPlaceholder_\(label)")
    }
}

